def parse_records(filepath: str):
    records = []
    with open(filepath, newline="", encoding="utf-8-sig") as f:
        reader = csv.reader(f)
        for row in reader:
            if len(row) < 3 or row[0].strip() != "Data" or row[2].strip() != "record":
                continue

            fields = {}
            i = 3
            while i + 2 < len(row):
                field_name = row[i].strip()
                field_value = row[i + 1].strip()
                if field_name and field_value:
                    fields[field_name] = field_value
                i += 3

            try:
                distance_m = float(fields.get("distance", 0))
                speed_ms = float(fields.get("speed", "0").split("|")[0])
                power = float(fields.get("power", 0))
                heart_rate = float(fields.get("heart_rate", 0))

                if distance_m > 0:
                    records.append({
                        "distance_m": distance_m,
                        "speed_ms": speed_ms,
                        "power": power,
                        "heart_rate": heart_rate,
                    })
            except (ValueError, KeyError, TypeError):
                continue

    return records

